import{_ as t,o,c as r,a2 as n}from"./chunks/framework.DTa47_fH.js";const g=JSON.parse('{"title":"Landing Zone Assessment","description":"","frontmatter":{},"headers":[],"relativePath":"assessment/landing-zone.md","filePath":"assessment/landing-zone.md"}'),s={name:"assessment/landing-zone.md"};function a(i,e,d,c,l,u){return o(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="landing-zone-assessment" tabindex="-1">Landing Zone Assessment <a class="header-anchor" href="#landing-zone-assessment" aria-label="Permalink to &quot;Landing Zone Assessment&quot;">​</a></h1><p>Landing Zone Assessment evaluates your cloud infrastructure configuration against the sovereignty requirements derived from your active compliance frameworks. It fetches the live service catalogue from your cloud provider and produces a structured fit/gap report showing which services and configurations meet the sovereign requirements and which do not.</p><p><strong>CLI:</strong> <code>swao assess --type landing-zone</code></p><p><strong>TUI:</strong> Main Menu &gt; Run Assessment &gt; [3] Landing Zone Assessment</p><hr><h2 id="what-it-produces" tabindex="-1">What it produces <a class="header-anchor" href="#what-it-produces" aria-label="Permalink to &quot;What it produces&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Output</th><th>What it contains</th></tr></thead><tbody><tr><td>Fit/gap report</td><td>Every landing zone control with COMPLIANT / GAP / PARTIAL status</td></tr><tr><td>Service catalogue snapshot</td><td>The cloud provider&#39;s sovereign service list at assessment time</td></tr><tr><td>Signal set</td><td>Structured findings mapped to compliance framework controls</td></tr><tr><td>BI export</td><td>Star schema entries for the portfolio Power BI dashboard</td></tr></tbody></table><hr><h2 id="supported-cloud-providers" tabindex="-1">Supported cloud providers <a class="header-anchor" href="#supported-cloud-providers" aria-label="Permalink to &quot;Supported cloud providers&quot;">​</a></h2><p>Landing Zone Assessment connects to the cloud provider service catalogue to validate which services are available in the sovereign region. Supported providers:</p><ul><li><strong>AWS</strong> -- sovereign and restricted regions</li><li><strong>Azure</strong> -- sovereign cloud and commercial regions with data-residency guarantees</li></ul><hr><h2 id="inputs-required" tabindex="-1">Inputs required <a class="header-anchor" href="#inputs-required" aria-label="Permalink to &quot;Inputs required&quot;">​</a></h2><p>Before running a Landing Zone Assessment, place your landing zone snapshot in the workspace:</p><ul><li><strong>IaC state file</strong> -- Terraform state (<code>terraform.tfstate</code>) or CloudFormation template</li><li><strong>CSP configuration export</strong> -- AWS Config snapshot or Azure Resource Graph export</li><li><strong>Network topology</strong> (optional) -- subnet, VPC, or VNET configuration for traffic-flow analysis</li></ul><p>SWAO reads these from <code>wsp/inputs/landing-zone/</code>. If the folder is absent or empty, SWAO uses the active compliance framework controls alone to generate a guidance-only report without a configuration-specific verdict.</p><hr><h2 id="how-scoring-works" tabindex="-1">How scoring works <a class="header-anchor" href="#how-scoring-works" aria-label="Permalink to &quot;How scoring works&quot;">​</a></h2><p>Each landing zone control maps to one or more framework requirements. SWAO compares the control&#39;s expected configuration against what it finds in your IaC or configuration snapshot:</p><ul><li><strong>COMPLIANT</strong> -- the configuration meets the sovereignty requirement.</li><li><strong>PARTIAL</strong> -- partially configured; specific gaps are documented.</li><li><strong>GAP</strong> -- the requirement is not met; remediation guidance is included.</li><li><strong>NOT ASSESSED</strong> -- insufficient configuration data to evaluate this control.</li></ul><p>The report groups findings by framework domain so a compliance reviewer can work through the gaps systematically.</p>',21)])])}const h=t(s,[["render",a]]);export{g as __pageData,h as default};
